struct Customer {
    arrival_time: u32,
    service_time: u32,
}

fn serve_customers(customers: Vec<Customer>) {
    let mut sorted = customers;
    sorted.sort_by_key(|c| c.arrival_time);
    let mut queue = VecDeque::from(sorted);

    let mut current_time = 0;
    let mut total_wait = 0;
    let mut processed = 0;

    while let Some(customer) = queue.pop_front() {
        let wait = current_time.saturating_sub(customer.arrival_time);
        total_wait += wait;
        processed += 1;
        current_time = current_time.max(customer.arrival_time) + customer.service_time;
    }

    let average = if processed == 0 {
        0.0
    } else {
        total_wait as f64 / processed as f64
    };

    println!("Average wait time: {:.2}", average);
}
