	tickers := []string{"AAPL", "GOOG", "MSFT"}
	updates := make(chan PriceUpdate)

	for _, ticker := range tickers {
		go func(t string) {
			for {
				price := rand.Float64()*100 + 100
				updates <- PriceUpdate{t, price}
				time.Sleep(time.Duration(rand.Intn(1500)+500) * time.Millisecond)
			}
		}(ticker)
	}

	averages := make(map[string]*AvgData)
	printTicker := time.NewTicker(5 * time.Second)
	defer printTicker.Stop()

	for {
		select {
		case update := <-updates:
			data, exists := averages[update.Ticker]
			if !exists {
				data = &AvgData{}
				averages[update.Ticker] = data
			}
			data.Sum += update.Price
			data.Count++
		case <-printTicker.C:
			for ticker, data := range averages {
				if data.Count > 0 {
					avg := data.Sum / float64(data.Count)
