use std::collections::LinkedList;

#[derive(Clone)]
pub struct Track {
    pub id: u32,
    pub name: String,
}

pub enum Operation {
    AddTrack(Track),
    RemoveTrack(u32),
    SkipNext,
    SkipPrevious,
    Reset,
}

pub struct PlaybackQueue {
    tracks: LinkedList<Track>,
    current: Option<usize>,
}

impl PlaybackQueue {
    pub fn new() -> Self {
        PlaybackQueue {
            tracks: LinkedList::new(),
            current: None,
        }
    }

    pub fn manage_playback_queue(&mut self, operation: Operation) {
        match operation {
            Operation::AddTrack(track) => {
                self.tracks.push_back(track);
                if self.current.is_none() {
                    self.current = Some(0);
                }
            }
            Operation::RemoveTrack(id) => {
                let original_current = self.current;
                let mut new_tracks = LinkedList::new();
                let mut kept_indices = Vec::new();
                let mut index = 0;
                for track in self.tracks.iter() {
                    if track.id != id {
                        new_tracks.push_back(track.clone());
                        kept_indices.push(index);
                    }
                    index += 1;
                }
                self.tracks = new_tracks;
                self.current = if self.tracks.is_empty() {
                    None
                } else {
                    original_current.and_then(|current| {
                        kept_indices
                            .iter()
                            .position(|&i| i == current)
                            .or(Some(0))
                    })
                };
            }
            Operation::SkipNext => {
                if let Some(current) = self.current {
                    if current + 1 < self.tracks.len() {
                        self.current = Some(current + 1);
                    }
                }
            }
            Operation::SkipPrevious => {
                if let Some(current) = self.current {
                    if current > 0 {
                        self.current = Some(current - 1);
                    }
                }
            }
            Operation::Reset => {
                if !self.tracks.is_empty() {
                    self.current = Some(0);
                } else {
                    self.current = None;
                }
            }
        }
    }
}
