use arrayvec::ArrayVec;

#[derive(Clone, Copy)]
struct StudentGrade {
    student_id: u32,
    grade: f32,
}

enum Operation {
    Add { id: u32, grade: f32 },
    Update { id: u32, grade: f32 },
    Delete { id: u32 },
    Average,
}

fn manage_student_grades<const N: usize>(
    grades: &mut ArrayVec<StudentGrade, N>,
    operation: Operation,
) -> Result<Option<f32>, &'static str> {
    match operation {
        Operation::Add { id, grade } => {
            if grades.is_full() {
                Err("Maximum capacity reached")
            } else {
                grades.push(StudentGrade { student_id: id, grade });
                Ok(None)
            }
        }
        Operation::Update { id, grade } => {
            let student = grades
                .iter_mut()
                .find(|s| s.student_id == id)
                .ok_or("Student ID not found")?;
            student.grade = grade;
            Ok(None)
        }
        Operation::Delete { id } => {
            let index = grades
                .iter()
                .position(|s| s.student_id == id)
                .ok_or("Student ID not found")?;
            grades.remove(index);
            Ok(None)
        }
        Operation::Average => {
            if grades.is_empty() {
                Ok(None)
            } else {
                let sum: f32 = grades.iter().map(|s| s.grade).sum();
                Ok(Some(sum / grades.len() as f32))
            }
        }
    }
}
