public class AnagramDetector {
    public static HashMap<String, Integer> detectAnagramOccurrences(String articleText, Set<String> words) {
        HashMap<Integer, HashMap<String, List<String>>> lengthMap = new HashMap<>();
        for (String word : words) {
            String sorted = sortWord(word);
            int len = word.length();
            lengthMap.putIfAbsent(len, new HashMap<>());
            lengthMap.get(len).computeIfAbsent(sorted, k -> new ArrayList<>()).add(word);
        }

        HashMap<String, Integer> result = new HashMap<>();
        words.forEach(word -> result.put(word, 0));

        for (int len : lengthMap.keySet()) {
            if (articleText.length() < len) continue;
            for (int i = 0; i <= articleText.length() - len; i++) {
                String sub = articleText.substring(i, i + len);
                String sortedSub = sortWord(sub);
                List<String> matches = lengthMap.get(len).getOrDefault(sortedSub, Collections.emptyList());
                matches.forEach(word -> result.put(word, result.get(word) + 1));
            }
        }

        return result;
    }

    private static String sortWord(String word) {
        char[] chars = word.toLowerCase().toCharArray();
        Arrays.sort(chars);
        return new String(chars);
    }
