vector<double> computeRollingAverages(const vector<double>& temperatures, int window_size) {
    int n = temperatures.size();
    vector<double> averages(n);
    for (int i = 0; i < n; ++i) {
        int start = max(0, i - window_size + 1);
        int end = i;
        double sum = 0.0;
        for (int j = start; j <= end; ++j) {
            sum += temperatures[j];
        }
        averages[i] = sum / (end - start + 1);
    }
    return averages;
}
