use std::collections::HashSet;

pub fn detect_cycle_in_graph(graph: &Vec<Vec<usize>>) -> bool {
    let mut visited = HashSet::new();
    let mut recursion_stack = HashSet::new();
    for node in 0..graph.len() {
        if !visited.contains(&node) {
            if dfs(node, graph, &mut visited, &mut recursion_stack) {
                return true;
            }
        }
    }
    false
}

fn dfs(
    node: usize,
    graph: &Vec<Vec<usize>>,
    visited: &mut HashSet<usize>,
    recursion_stack: &mut HashSet<usize>,
) -> bool {
    if recursion_stack.contains(&node) {
        return true;
    }
    if visited.contains(&node) {
        return false;
    }
    visited.insert(node);
    recursion_stack.insert(node);
    for &neighbor in &graph[node] {
        if dfs(neighbor, graph, visited, recursion_stack) {
            return true;
        }
    }
    recursion_stack.remove(&node);
    false
}
