public class MeetingScheduler {
    public static ArrayList<Meeting> organizeMeetings(List<Meeting> meetings) {
        PriorityQueue<Meeting> queue = new PriorityQueue<>();
        queue.addAll(meetings);
        ArrayList<Meeting> processed = new ArrayList<>();
        while (!queue.isEmpty()) {
            processed.add(queue.poll());
        }
        return processed;
    }

    public static class Meeting implements Comparable<Meeting> {
        private int urgency;

        public Meeting(int urgency) {
            this.urgency = urgency;
        }

        @Override
        public int compareTo(Meeting other) {
            return Integer.compare(other.urgency, this.urgency);
        }
    }
}
